const res = $input.first().json;
const rows = res.values || [];

const ready = rows
  .map((r, i) => ({
    rowIndex: i + 2,
    status: (r[3] || '').toUpperCase().trim(),
    job_id: r[0] || '',
    topic: r[1] || '',
    title: r[2] || '',
    payloadJson: r[4] || '',
    driveFileId: r[5] || '',
    driveUrl: r[6] || '',
    hashtags: r[7] || '',
    sheetRow: r[8] || ''
  }))
  .filter(r => r.status === 'READY_TO_PUBLISH' && r.job_id);

if (ready.length === 0) {
  return [{ json: { stop: true, reason: 'NO_READY_JOBS' } }];
}

const job = ready[0];
let payload = {};
try { payload = JSON.parse(job.payloadJson); } catch (e) {}

return [{ json: {
  stop: false,
  rowIndex: job.rowIndex,
  job_id: job.job_id,
  title: job.title || job.topic,
  topic: job.topic,
  narration: payload.narration || '',
  hashtags: job.hashtags || '#QuantumPhysics #Physics #Science',
  drive_file_id: job.driveFileId,
  drive_video_url: job.driveUrl,
  sheet_row: job.sheetRow
}}];

const data = $input.first().json;
const topic = data.topic || data.title || 'Quantum Physics';
const narration = (data.narration || '').replace(/_/g, ' ').replace(/\s*--\s*/g, ' ').replace(/\s*-\s*/g, ' ').replace(/"/g, "'").replace(/\s+/g, ' ').trim().slice(0, 400);
const hashtags = (data.hashtags || '#QuantumPhysics #Physics #Science').replace(/"/g, '');

const prompt = 'Create engaging social media captions for a quantum physics short video.

Topic: ' + topic + '
Narration: ' + narration + '

Rules:
- facebook_caption: 3 engaging paragraphs. Start with the physics fact as a hook. Second paragraph explains why it matters. Third paragraph ends with awe or implication. No hashtags. No underscores. No dashes. Plain readable sentences only.
- instagram_caption: 2-3 short punchy sentences. Hook first. No underscores or dashes.
- linkedin_caption: 2-3 professional sentences about the scientific significance. No underscores or dashes.
- youtube_title: Catchy title max 60 chars, no special symbols.
- youtube_description: 2-3 clear sentences.

Return ONLY valid JSON (no markdown, no code fences):
{
  "facebook_caption": "3 paragraphs here",
  "youtube_title": "title here",
  "youtube_description": "description here",
  "instagram_caption": "short punchy caption",
  "linkedin_caption": "professional caption",
  "generated_hashtags": "' + hashtags + '"
}';

return [{ json: {
  ...data,
  claude_payload: {
    model: 'claude-haiku-4-5-20251001',
    max_tokens: 2048,
    messages: [{ role: 'user', content: prompt }]
  }
}}];

function parseJ(raw) {
  const t = (raw||'').trim().replace(/^```json\s*/i,'').replace(/^```\s*/i,'').replace(/```\s*$/i,'').trim();
  return JSON.parse(t);
}
const prev = $('Build Caption Prompt').first().json;
const text = $input.first().json?.content?.[0]?.text || '';
let caps = {};
try { caps = parseJ(text); } catch(e) {
  caps = {
    facebook_caption: prev.narration || prev.topic,
    youtube_title: (prev.title || prev.topic || 'Physics Short').slice(0,60),
    youtube_description: prev.narration || '',
    instagram_caption: prev.narration || prev.topic,
    linkedin_caption: prev.narration || prev.topic,
    generated_hashtags: prev.hashtags || '#QuantumPhysics #Physics'
  };
}
return [{ json: { ...prev, ...caps } }];

const { execSync } = require('child_process');
const data = $input.first().json;
const jobId = data.job_id;
const driveId = data.drive_file_id;
if (!driveId) throw new Error('No drive_file_id for job: ' + jobId);

function run(cmd, t) {
  try { return execSync(cmd, { encoding: 'utf-8', timeout: t || 120000 }); }
  catch(e) { return ((e.stdout||'') + (e.stderr||'')).toString(); }
}

const localPath = '/ffmpeg/input/' + jobId + '_pub.mp4';
const n8nPath   = '/data/ffmpeg/input/' + jobId + '_pub.mp4';

// Skip download if already cached
if (!run('docker exec phys_ffmpeg_runner test -f "' + localPath + '" && echo OK').includes('OK')) {
  const dlUrl = 'https://drive.google.com/uc?export=download&id=' + driveId + '&confirm=t';
  console.log('Downloading job ' + jobId + ' from Drive...');
  const out = run('docker exec phys_ffmpeg_runner curl -L --max-time 300 -o "' + localPath + '" "' + dlUrl + '" && echo DL_OK', 310000);
  if (!run('docker exec phys_ffmpeg_runner test -f "' + localPath + '" && echo OK').includes('OK')) {
    throw new Error('Drive download failed for ' + jobId + ': ' + out.slice(-300));
  }
  console.log('Downloaded ' + jobId + ' OK');
}

return [{ json: { ...data, local_video_path: n8nPath, ffmpeg_video_path: localPath } }];

const { spawnSync } = require('child_process');
const fs = require('fs');
const data = $input.first().json;
const pageId = $env.FB_PAGE_ID;
const token  = $env.FB_PAGE_ACCESS_TOKEN;
const videoPath = data.ffmpeg_video_path;

const title = (data.title || data.topic || 'Physics').slice(0, 255);
const desc  = ((data.facebook_caption || '') + '\n\n' + (data.generated_hashtags || '')).slice(0, 5000);

fs.writeFileSync('/tmp/fb_desc.txt', desc);
spawnSync('docker', ['cp', '/tmp/fb_desc.txt', 'phys_ffmpeg_runner:/tmp/fb_desc.txt']);

const result = spawnSync('docker', [
  'exec', 'phys_ffmpeg_runner',
  'curl', '-s', '--max-time', '300',
  '-X', 'POST',
  'https://graph-video.facebook.com/v18.0/' + pageId + '/videos',
  '-F', 'access_token=' + token,
  '-F', 'title=' + title,
  '-F', 'description=</tmp/fb_desc.txt',
  '-F', 'source=@' + videoPath
], { timeout: 320000 });

const output = (result.stdout || Buffer.from('')).toString().trim();
console.log('FB response: ' + output.slice(0, 200));

let parsed = {};
try { parsed = JSON.parse(output); } catch(e) {}
const fbVideoId = parsed.id || null;
const fbUrl = fbVideoId ? 'https://www.facebook.com/video/' + fbVideoId : null;

return [{ json: { ...data, fb_video_id: fbVideoId, fb_post_url: fbUrl, fb_status: fbVideoId ? 'OK' : 'FAILED', fb_error: parsed.error ? JSON.stringify(parsed.error) : null } }];

const { spawnSync } = require('child_process');
const https = require('https');
const fs = require('fs');
const data = $input.first().json;

const clientId     = $env.YOUTUBE_OAUTH_CLIENT_ID;
const clientSecret = $env.YOUTUBE_OAUTH_CLIENT_SECRET;
const refreshToken = $env.YOUTUBE_REFRESH_TOKEN;

if (!clientId || !clientSecret || !refreshToken)
  return [{ json: { ...data, yt_status: 'SKIP', yt_video_url: null, yt_error: 'Missing YT env vars' } }];

// Get access token
const tokenBody = 'grant_type=refresh_token&client_id=' + encodeURIComponent(clientId) +
  '&client_secret=' + encodeURIComponent(clientSecret) +
  '&refresh_token=' + encodeURIComponent(refreshToken);

const tokenRes = await new Promise((resolve, reject) => {
  const req = https.request({
    hostname: 'oauth2.googleapis.com', path: '/token', method: 'POST',
    headers: { 'Content-Type': 'application/x-www-form-urlencoded', 'Content-Length': Buffer.byteLength(tokenBody) }
  }, res => { let b=''; res.on('data',c=>b+=c); res.on('end',()=>resolve({status:res.statusCode,body:b})); });
  req.on('error', reject); req.write(tokenBody); req.end();
});

const tokenData = JSON.parse(tokenRes.body);
if (!tokenData.access_token)
  return [{ json: { ...data, yt_status: 'SKIP', yt_video_url: null, yt_error: 'Token failed: ' + tokenRes.body.slice(0,200) } }];

const accessToken = tokenData.access_token;
const title = ((data.youtube_title || data.title || 'Physics Short') + ' #Shorts').slice(0, 100);
const desc  = ((data.youtube_description || data.narration || '') + '\n\n' + (data.generated_hashtags || '')).slice(0, 5000);

const metadata = JSON.stringify({
  snippet: { title, description: desc, tags: ['physics','science','shorts','quantum'], categoryId: '28' },
  status: { privacyStatus: 'public', selfDeclaredMadeForKids: false }
});

// Resumable upload init
const initRes = await new Promise((resolve, reject) => {
  const req = https.request({
    hostname: 'www.googleapis.com',
    path: '/upload/youtube/v3/videos?uploadType=resumable&part=snippet,status',
    method: 'POST',
    headers: {
      'Authorization': 'Bearer ' + accessToken,
      'Content-Type': 'application/json; charset=UTF-8',
      'X-Upload-Content-Type': 'video/mp4',
      'Content-Length': Buffer.byteLength(metadata)
    }
  }, res => { let b=''; res.on('data',c=>b+=c); res.on('end',()=>resolve({status:res.statusCode,headers:res.headers,body:b})); });
  req.on('error', reject); req.write(metadata); req.end();
});

const uploadUrl = initRes.headers.location;
if (!uploadUrl) return [{ json: { ...data, yt_status: 'SKIP', yt_video_url: null, yt_error: 'No upload URL: ' + initRes.body.slice(0,200) } }];

// Upload file via curl (handles large files)
const localPath = data.ffmpeg_video_path;
const curlRes = spawnSync('docker', [
  'exec', 'phys_ffmpeg_runner',
  'curl', '-s', '--max-time', '600',
  '-X', 'PUT', uploadUrl,
  '-H', 'Content-Type: video/mp4',
  '--data-binary', '@' + localPath
], { timeout: 610000 });

let ytParsed = {};
try { ytParsed = JSON.parse((curlRes.stdout||Buffer.from('')).toString()); } catch(e) {}
const ytId = ytParsed.id || null;
const ytUrl = ytId ? 'https://www.youtube.com/shorts/' + ytId : null;

return [{ json: { ...data, yt_video_id: ytId, yt_video_url: ytUrl, yt_status: ytId ? 'OK' : 'FAILED' } }];

const data = $input.first().json;
const rowIndex = data.rowIndex;
const socialUrls = 'FB:' + (data.fb_post_url||'SKIP') + ' | YT:' + (data.yt_video_url||'SKIP');
return [{ json: { ...data, socialUrls, updateRowIndex: rowIndex } }];

const ytData = $("YT Upload").first().json;
const liResult = $input.first().json || {};
const liFailed = !!(liResult.error || liResult.code);
return [{ json: { ...ytData, li_status: liFailed ? "FAILED" : "OK", li_post_url: liResult.post_url || liResult.url || null } }];

const https = require('https');
const data = $input.first().json;

const apiKey = $env.POSTFORME_API_KEY;
if (!apiKey) throw new Error('POSTFORME_API_KEY not set');

const videoUrl = 'https://drive.google.com/uc?export=download&id=' + data.drive_file_id + '&confirm=t';
const caption  = ((data.instagram_caption || data.title || data.topic || '') + '\n\n' + (data.generated_hashtags || '')).slice(0, 2190);

const postBody = JSON.stringify({
  caption: caption,
  social_accounts: [$env.POSTFORME_PHYSICS_IG_ACCOUNT_ID, $env.POSTFORME_PHYSICS_TIKTOK_ACCOUNT_ID, $env.POSTFORME_PHYSICS_LI_ACCOUNT_ID],
  media: [{ url: videoUrl }]
});

const result = await new Promise((resolve, reject) => {
  const buf = Buffer.from(postBody);
  const req = https.request({
    hostname: 'api.postforme.dev',
    path: '/v1/social-posts',
    method: 'POST',
    headers: {
      'Authorization': 'Bearer ' + apiKey,
      'Content-Type': 'application/json',
      'Content-Length': buf.length
    }
  }, res => {
    let d = ''; res.on('data', c => d += c);
    res.on('end', () => { try { resolve(JSON.parse(d)); } catch(e) { reject(new Error('Non-JSON: ' + d.slice(0,200))); } });
  });
  req.on('error', reject);
  req.write(buf); req.end();
});

console.log('PostForMe result:', JSON.stringify(result).slice(0, 300));
if (result.status === 'error') throw new Error('PostForMe error: ' + (result.message || JSON.stringify(result)));

return [{ json: { ...data, postforme_ig_url: result.postIds?.find(p=>p.platform==='instagram')?.postUrl || '', postforme_tiktok_url: result.postIds?.find(p=>p.platform==='tiktok')?.postUrl || '' } }];
